dth:768px) {\n                    grid-column-gap: 20px;\n                    grid-row-gap: 20px;\n                }\n                .gfield {\n                    &.gfield_error {\n                        .gfield_label {\n                            color: inherit;\n                        }\n                    }\n                    .gfield_label {\n                        margin-bottom: 5px;\n                        font-size: 1.125rem;\n                        line-height: 1.5;\n                        font-weight: normal;\n                    }\n                    .gfield_required {\n                        font-size: 1.125rem;\n                    }\n\t\t\t\t\tlabel.gform-field-label {\n\t\t\t\t\t\tfont-size: 1.125rem;\n                        line-height: 1.5;\n                        font-weight: normal;\n\t\t\t\t\t\tcursor: pointer;\n\t\t\t\t\t}\n                    input[type=text], \n                    input[type=email], \n                    input[type=url], \n                    input[type=password], \n                    input[type=tel], \n                    input[type=search],\n                    input[type=number],\n                    textarea,\n                    select {\n                        height: 40px;\n                        padding: 10px;\n                        font-size: 1.125rem;\n                        line-height: 1;\n                        color: inherit;\n                        border: none;\n                        border-radius: 10px;\n                        background-color: #fff;\n                        -webkit-appearance: none;\n\t\t\t\t\t\tborder: 1px solid #fff;\n                        &:focus {\n\t\t\t\t\t\t\toutline: none;\n                            border-color: var( --e-global-color-primary );\n                        }\n                    }\n                    .ginput_container_textarea {\n                        textarea {\n                            min-height: 94px;\n                        }\n                    }\n\t\t\t\t\t.gfield_radio {\n\t\t\t\t\t\t.gchoice {\n\t\t\t\t\t\t\tmargin-bottom: 5px;\n\t\t\t\t\t\t\tinput[type=radio] {\n\t\t\t\t\t\t\t\tdisplay: none;\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t\tinput[type=radio]:checked + label::after {\n\t\t\t\t\t\t\t\tdisplay: block;\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t\tlabel {\n\t\t\t\t\t\t\t\tposition: relative;\n\t\t\t\t\t\t\t\tdisplay: flex;\n\t\t\t\t\t\t\t\talign-items: center;\n\t\t\t\t\t\t\t\tgap: 10px;\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t\tlabel::before {\n\t\t\t\t\t\t\t\tcontent: \"\";\n\t\t\t\t\t\t\t\tdisplay: block;\n\t\t\t\t\t\t\t\twidth: 18px;\n\t\t\t\t\t\t\t\theight: 18px;\n\t\t\t\t\t\t\t\tborder: 1px solid var( --e-global-color-text );\n\t\t\t\t\t\t\t\tbackground-color: transparent;\n\t\t\t\t\t\t\t\tborder-radius: 100%;\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t\tlabel::after {\n\t\t\t\t\t\t\t\tdisplay: none;\n\t\t\t\t\t\t\t\tposition: absolute;\n\t\t\t\t\t\t\t\tcontent: \"\";\n\t\t\t\t\t\t\t\twidth: 10px;\n\t\t\t\t\t\t\t\theight: 10px;\n\t\t\t\t\t\t\t\tbackground-color: var(--e-global-color-text);\n\t\t\t\t\t\t\t\tborder-radius: 100%;\n\t\t\t\t\t\t\t\tleft: 4px;\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t}\n\t\t\t\t\t\t\n\t\t\t\t\t}\n\t\t\t\t\t.gfield_checkbox {\n\t\t\t\t\t\t.gchoice {\n\t\t\t\t\t\t\tposition: relative;\n\t\t\t\t\t\t\tmargin-left: 26px;\n\t\t\t\t\t\t\tinput {\n\t\t\t\t\t\t\t\twidth: 15px;\n\t\t\t\t\t\t\t\theight: 15px;\n\t\t\t\t\t\t\t\tmargin: 0;\n\t\t\t\t\t\t\t\tcursor: pointer;\n\t\t\t\t\t\t\t\tposition: absolute;\n\t\t\t\t\t\t\t\tleft: -26px;\n\t\t\t\t\t\t\t\ttop: 9px;\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t\tinput:checked+label::before {\n\t\t\t\t\t\t\t\tdisplay: block;\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t\tlabel {\n\t\t\t\t\t\t\t\t&::before{\n\t\t\t\t\t\t\t\t\tcontent: \"\";\n\t\t\t\t\t\t\t\t\tposition: absolute;\n\t\t\t\t\t\t\t\t\tleft: -26px;\n\t\t\t\t\t\t\t\t\ttop: 9px;\n\t\t\t\t\t\t\t\t\tdisplay: none;\n\t\t\t\t\t\t\t\t\twidth: 15px;\n\t\t\t\t\t\t\t\t\theight: 15px;\n\t\t\t\t\t\t\t\t\tbackground-color: var(--e-global-color-secondary);\n\t\t\t\t\t\t\t\t\tborder-radius: 3px;\n\t\t\t\t\t\t\t\t\tbackground-image: url(data:image/svg+xml;base64,\n\t);\n\t\t\t\t\t\t\t\t\tbackground-repeat: no-repeat;\n\t\t\t\t\t\t\t\t\tbackground-position: center;\n\t\t\t\t\t\t\t\t\tbackground-size: 11px;\n\t\t\t\t\t\t\t\t}\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n                    .ginput_container_select {\n                        position: relative;\n                        select {\n                            width: 100%;\n                            cursor: pointer;\n\t\t\t\t\t\t\tfont-size: 1rem;\n                        }\n                        &::after {\n                            content: \"\";\n                            display: block;\n                            width: 12px;\n                            height: 12px;\n                            position: absolute;\n                            right: 15px;\n                            top: 50%;\n                            transform: translateY(-50%);\n                            z-index: 10;\n                            background-image: url(\"/wp-content/uploads/2026/05/gray-chevron-down.svg\");\n                            background-repeat: no-repeat;\n                            background-size: contain;\n                            background-position: center;\n                        }\n                    }\n                    .gfield_description.validation_message {\n                        margin-top: 5px;\n\t\t\t\t\t\tpadding: 0;\n\t\t\t\t\t\tborder: none;\n\t\t\t\t\t\tbackground-color: transparent;\n\t\t\t\t\t\tfont-size: 0.9rem;\n\t\t\t\t\t\twidth: fit-content;\n                    }\n                }\n            }\n        }\n        .gform_footer {\n            width: 100%;\n            padding: 0 !important;\n            margin: 40px 0 0 !important;\n            position: relative;\n            @media (max-width: 767px) {\n                margin: 24px 0 0 !important;\n            }\n            input[type=submit] {\n\t\t\t\twidth: 100%;\n                border: none;\n\t\t\t\tbackground-color: var( --e-global-color-secondary );\n\t\t\t\t&:hover {\n\t\t\t\t\tbackground-color: var( --e-global-color-primary );\n\t\t\t\t}\n\t\t\t\ttransition: all 0.3s;\n\t\t\t\t@media (max-width: 767px) {\n\t\t\t\t\tfont-size: 1rem;\n\t\t\t\t}\n            }\n            .gform-loader {\n                position: absolute;\n                z-index: 10;\n                right: 20px;\n\t\t\t\ttop: 16px;\n\t\t\t\twidth: 20px;\n\t\t\t\theight: 20px;\n            }\n        }\n    }\n}\n.gform_confirmation_wrapper {\n\t.gform_confirmation_message {\n\t\tcolor: #333;\n\t\tfont-size: 1.125rem;\n\t\twidth: 100%;\n\t\ttext-align: center;\n\t}\n}\n}\n\n\nbody .gform_wrapper.worksheet-form_wrapper {\n    background-color: #C6EFFE;\n    padding: 40px;\n    border-radius: 40px;\n\n    @media (max-width: 768px) {\n        padding: 30px 20px;\n    }\n\n    form.worksheet-form {\n        .gform_footer {\n            margin-top: 30px !important;\n            input[type=submit] {\n                background-color: #005375;\n                margin-bottom: 0;\n            \n\n                &:hover {\n                    background-color: #0091B3;\n                }\n\n                &:active {\n                    transform: scale(0.98);\n                }\n            }\n        }\n    }\n}","body .gform_wrapper {\n  font-family: var(--e-global-typography-text-font-family, \"Plus Jakarta Sans\");\n  color: var(--e-global-color-text, #231F20);\n  background-color: transparent;\n  height: 100%;\n}\nbody .gform_wrapper .gform_validation_errors {\n  display: none;\n}\nbody .gform_wrapper .gform_heading {\n  display: none;\n}\nbody .gform_wrapper form {\n  margin: 0;\n  height: 100%;\n  display: flex;\n  flex-direction: column;\n  justify-content: space-between;\n  background-color: transparent;\n}\nbody .gform_wrapper form .gform_body .gform_fields {\n  grid-column-gap: 24px;\n  grid-row-gap: 24px;\n}\n@media (max-width: