    transition: all 0.3s ease;\n            outline: none;\n            text-align: left;\n            border-radius: 0;\n            \n            @media (max-width: 1024px) {\n                padding: 20px 0;\n            }\n\n            .course-accordion-title {\n                margin: 0;\n                flex: 1;\n                padding-right: 20px;\n                font-family: var(--e-global-typography-secondary-font-family);\n                font-size: 1.875rem;\n                font-weight: 600;\n                color: var(--e-global-color-text);\n                line-height: 1.1;\n                white-space: normal;\n                word-break: break-word;\n                \n                @media (max-width: 1024px) {\n                    font-size: 1.25rem;\n                }\n            }\n\n            .course-accordion-icon {\n                display: flex;\n                align-items: center;\n                justify-content: center;\n                color: #1E1E1E;\n                flex-shrink: 0;\n                \n                svg {\n                    width: 19px;\n                    height: auto;\n                    transition: transform 0.3s ease;\n                    display: block;\n                }\n            }\n        }\n\n        .course-accordion-header.active .course-accordion-icon svg {\n            transform: rotate(180deg);\n        }\n        \n        .course-accordion-icon .elementor-accordion-icon-opened {\n            display: none;\n        }\n        \n        .course-accordion-header.active .course-accordion-icon .elementor-accordion-icon-closed:has(+ .elementor-accordion-icon-opened) {\n            display: none;\n        }\n        \n        .course-accordion-header.active .course-accordion-icon .elementor-accordion-icon-opened {\n            display: block;\n        }\n\n        .course-accordion-content {\n            display: none;\n            padding-bottom: 30px;\n\n            .course-accordion-content-inner {\n                color: var(--e-global-color-text);\n                font-size: 1.125rem;\n                line-height: 1.6;\n                font-family: var(--e-global-typography-primary-font-family);\n                \n                @media (max-width: 1024px) {\n                    font-size: 1rem;\n                }  \n            }\n\n            // Steps (Topics & Quizzes) List\n            .course-accordion-steps {\n                list-style: none;\n                margin: 0;\n                padding: 0;\n                display: flex;\n                flex-direction: column;\n                gap: 12px;\n\n                .course-accordion-step-item {\n                    display: flex;\n                    align-items: center;\n                    gap: 10px;\n                    font-size: 1rem;\n                    color: #577282;\n                    transition: color 0.2s ease;\n\n                    .step-icon {\n                        display: flex;\n                        align-items: center;\n                        justify-content: center;\n                        color: #9275D9; // Purple accent\n                        flex-shrink: 0;\n\n                        svg {\n                            width: 16px;\n                            height: 16px;\n                            display: block;\n                        }\n                    }\n\n                    .step-title {\n                        line-height: 1.4;\n                    }\n\n                    a {\n                        color: inherit;\n                        text-decoration: none;\n                        display: inline-flex;\n                        align-items: center;\n                        gap: 10px;\n                        width: 100%;\n\n                        &:hover {\n                            color: #9275D9;\n                        }\n                    }\n                }\n            }\n        }\n    }\n}\n\n"],"names":[],"sourceRoot":""}
